namespace sv_3a332e6e0592441bab422ff1a7f6d905.Services;

public class WarehouseInfo
{
    public string WarehouseId { get; set; } = "WH-001";
    public string WarehouseName { get; set; } = "Warehouse A";

    public static readonly (string Id, string Name)[] AvailableWarehouses =
    [
        ("WH-001", "Warehouse A"),
        ("WH-002", "Warehouse B"),
        ("WH-003", "Warehouse C"),
    ];
}

namespace sv_3a332e6e0592441bab422ff1a7f6d905.Services;

/// <summary>
/// Scoped service (per circuit) that tracks low-stock alert counts and
/// notifies all subscribed components when the count changes.
/// </summary>
