@rendermode InteractiveServer
@inject CascadingValueSource<WarehouseInfo> WarehouseSource
@inject InventoryAlertService AlertService
@using sv_3a332e6e0592441bab422ff1a7f6d905.Services

<select class="form-select form-select-sm" style="width: 200px;"
        value="@_selectedId" @onchange="OnWarehouseChanged">
    @foreach (var (id, name) in WarehouseInfo.AvailableWarehouses)
    {
        <option value="@id">@name</option>
    }
</select>

@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private string _selectedId = "WH-001";

    protected override void OnParametersSet()
    {
        if (Warehouse is not null)
        {
            _selectedId = Warehouse.WarehouseId;
        }
    }

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        var newId = e.Value?.ToString() ?? "WH-001";
        var match = WarehouseInfo.AvailableWarehouses
            .FirstOrDefault(w => w.Id == newId);

        var info = new WarehouseInfo
        {
            WarehouseId = match.Id ?? newId,
            WarehouseName = match.Name ?? newId,
        };

        _selectedId = info.WarehouseId;

        // Push the new warehouse to every [CascadingParameter] subscriber
        await WarehouseSource.NotifyChangedAsync(info);

        // Immediately refresh alert count for the new warehouse
        await AlertService.RefreshAsync(info.WarehouseId);
    }
}

