@page "/dashboard"
@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@implements IDisposable
@using sv_3a332e6e0592441bab422ff1a7f6d905.Services

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<p>
    Currently viewing: <strong>@(Warehouse?.WarehouseName ?? "—")</strong>
    (<code>@(Warehouse?.WarehouseId ?? "—")</code>)
</p>

<div class="card" style="max-width: 400px;">
    <div class="card-body">
        <h5 class="card-title">Low-Stock Alerts</h5>
        <p class="card-text display-4">
            @AlertService.CurrentLowStockCount
        </p>
        <p class="text-muted">
            Items below minimum level &middot; refreshes every 10 s
        </p>
    </div>
</div>

@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private Action? _handler;

    protected override void OnInitialized()
    {
        // Subscribe so this component re-renders when any source triggers a refresh
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnChange += _handler;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            // Kick off initial load + start polling
            if (Warehouse is not null)
            {
                await AlertService.RefreshAsync(Warehouse.WarehouseId);
            }

            _cts = new CancellationTokenSource();
            _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
            _ = PollAsync(_cts.Token);
        }
    }

    private async Task PollAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                if (Warehouse is not null)
                {
                    // RefreshAsync updates the count AND fires OnChange,
                    // which re-renders every subscribed component.
                    await AlertService.RefreshAsync(Warehouse.WarehouseId);
                }
            }
        }
        catch (OperationCanceledException)
        {
            // Normal shutdown — timer was disposed or token cancelled
        }
    }

    public void Dispose()
    {
        AlertService.OnChange -= _handler;
        _cts?.Cancel();
        _cts?.Dispose();
        _timer?.Dispose();
    }
}

